#!/usr/bin/env python3\n\"\"\"\nTest script for DEV_MODE schema caching functionality.\n\nThis script demonstrates how to:\n1. Enable/disable DEV_MODE\n2. Test schema caching behavior\n3. Monitor cache status\n\nUsage:\n    python test_dev_mode.py\n\"\"\"\n\nimport os\nimport sys\nfrom pathlib import Path\n\n# Add the project root to Python path\nproject_root = Path(__file__).parent\nsys.path.insert(0, str(project_root))\n\n# Import the db_query module\ntry:\n    from db_query import (\n        enable_dev_mode,\n        disable_dev_mode,\n        get_dev_mode_status,\n        test_dev_mode_caching,\n        get_universal_schema,\n        clear_schema_cache\n    )\nexcept ImportError as e:\n    print(f\"Error importing db_query module: {e}\")\n    print(\"Make sure you're running this from the project root directory.\")\n    sys.exit(1)\n\ndef main():\n    print(\"=\" * 60)\n    print(\"DEV_MODE Schema Caching Test\")\n    print(\"=\" * 60)\n    \n    # Check initial status\n    print(\"\\n1. Initial DEV_MODE Status:\")\n    status = get_dev_mode_status()\n    print(f\"   DEV_MODE Enabled: {status['dev_mode_enabled']}\")\n    print(f\"   Schema Cached: {status['schema_cached']}\")\n    print(f\"   Cached Tables: {status['cached_tables']}\")\n    \n    # Test the full caching workflow\n    print(\"\\n2. Running DEV_MODE Caching Test:\")\n    try:\n        final_status = test_dev_mode_caching()\n        print(f\"\\n   Test completed successfully!\")\n        print(f\"   Final status: {final_status}\")\n    except Exception as e:\n        print(f\"   Test failed with error: {e}\")\n        return False\n    \n    # Manual test - enable DEV_MODE and test multiple calls\n    print(\"\\n3. Manual DEV_MODE Test:\")\n    try:\n        # Clear any existing cache\n        clear_schema_cache()\n        \n        # Enable DEV_MODE\n        enable_dev_mode()\n        \n        # First call - should hit database\n        print(\"   First schema call (should hit database):\")\n        schema1 = get_universal_schema()\n        if schema1['success']:\n            print(f\"   ✅ Schema loaded with {len(schema1['tables'])} tables\")\n        else:\n            print(f\"   ❌ Schema loading failed: {schema1.get('error', 'Unknown error')}\")\n        \n        # Second call - should use cache\n        print(\"   Second schema call (should use cache):\")\n        schema2 = get_universal_schema()\n        if schema2['success']:\n            print(f\"   ✅ Schema loaded with {len(schema2['tables'])} tables (from cache)\")\n        else:\n            print(f\"   ❌ Schema loading failed: {schema2.get('error', 'Unknown error')}\")\n        \n        # Check final status\n        final_status = get_dev_mode_status()\n        print(f\"   Final status: {final_status}\")\n        \n        # Disable DEV_MODE\n        disable_dev_mode()\n        \n        return True\n        \n    except Exception as e:\n        print(f\"   Manual test failed with error: {e}\")\n        return False\n\nif __name__ == \"__main__\":\n    success = main()\n    \n    print(\"\\n\" + \"=\" * 60)\n    if success:\n        print(\"✅ All DEV_MODE tests completed successfully!\")\n        print(\"\\nTo enable DEV_MODE in your application:\")\n        print(\"1. Set DEV_MODE=true in your .env file, or\")\n        print(\"2. Call enable_dev_mode() in your code\")\n        print(\"\\nBenefits:\")\n        print(\"- Faster application startup during development\")\n        print(\"- Reduced database load during frequent reloads\")\n        print(\"- Schema cached in memory until application restart\")\n    else:\n        print(\"❌ Some tests failed. Check the error messages above.\")\n    print(\"=\" * 60)